import React, { useState, useEffect, useContext, useRef, useCallback } from 'react';
import { chatAPI, authAPI } from '../services/api';
import { AuthContext } from '../context/AuthContext';
import io from 'socket.io-client';

const ChatPage = () => {
  const { user } = useContext(AuthContext);
  const [users, setUsers] = useState([]);
  const [selectedUser, setSelectedUser] = useState(null);
  const [messages, setMessages] = useState([]);
  const [newMessage, setNewMessage] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [isChatbot, setIsChatbot] = useState(false);
  const [chatbotLoading, setChatbotLoading] = useState(false);
  const [unreadCounts, setUnreadCounts] = useState({});
  const [notificationText, setNotificationText] = useState('');
  const socket = useRef(null);
  const messagesEndRef = useRef(null);
  const selectedUserRef = useRef(null);
  const isChatbotRef = useRef(false);
  const usersRef = useRef([]);

  // Message handler callback
  const handleReceiveMessage = useCallback((data) => {
    const activeUserId = selectedUserRef.current?._id;
    const isChatbotActive = isChatbotRef.current;
    const isActiveChat = data.senderId === activeUserId && !isChatbotActive;

    if (isActiveChat) {
      setMessages((prev) => [...prev, data]);
      return;
    }

    setUnreadCounts((prev) => ({
      ...prev,
      [data.senderId]: (prev[data.senderId] || 0) + 1,
    }));

    const sender = usersRef.current.find((item) => item._id === data.senderId);
    const senderName = sender?.name || 'New message';
    setNotificationText(`New message from ${senderName}`);

    if ('Notification' in window && Notification.permission === 'granted') {
      new Notification(`Message from ${senderName}`, {
        body: data.message,
      });
    }
  }, []);

  // Initialize socket connection
  useEffect(() => {
    socket.current = io('http://localhost:5000', {
      auth: {
        token: localStorage.getItem('token'),
      },
    });

    socket.current.emit('user_join', user?._id);

    socket.current.on('receive_message', handleReceiveMessage);

    return () => {
      socket.current.off('receive_message', handleReceiveMessage);
      socket.current.disconnect();
    };
  }, [user, handleReceiveMessage]);

  useEffect(() => {
    selectedUserRef.current = selectedUser;
    isChatbotRef.current = isChatbot;
  }, [selectedUser, isChatbot]);

  useEffect(() => {
    usersRef.current = users;
  }, [users]);

  useEffect(() => {
    if ('Notification' in window && Notification.permission === 'default') {
      Notification.requestPermission();
    }
  }, []);

  useEffect(() => {
    if (!notificationText) return undefined;
    const timer = setTimeout(() => setNotificationText(''), 3000);
    return () => clearTimeout(timer);
  }, [notificationText]);

  // Scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  useEffect(() => {
    fetchUsers();
  }, []);

  const fetchUsers = async () => {
    try {
      const res = await authAPI.getAllStaff();
      const staff = res.data.staff || [];
      // Add chatbot as a special user
      const chatbot = { _id: 'chatbot', name: 'AI Assistant', subject: 'Doubt Resolution Bot' };
      setUsers([chatbot, ...staff]);
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to fetch users');
    }
  };

  const handleSelectUser = async (staffMember) => {
    setSelectedUser(staffMember);
    setIsChatbot(staffMember._id === 'chatbot');
    setUnreadCounts((prev) => ({
      ...prev,
      [staffMember._id]: 0,
    }));
    if (staffMember._id === 'chatbot') {
      setMessages([
        {
          senderId: 'chatbot',
          senderName: 'AI Assistant',
          message: 'Hello! I\'m an AI assistant here to help with your academic questions and doubts. I can provide explanations, answer questions, and guide you through various subjects. If your question requires personalized attention or expert knowledge, I\'ll recommend consulting with a staff member. What can I help you with today?',
          timestamp: new Date().toISOString(),
        },
      ]);
      setLoading(false);
    } else {
      setLoading(true);
      try {
        const res = await chatAPI.getChatHistory(staffMember._id);
        setMessages(res.data.messages || []);
      } catch (err) {
        setError(err.response?.data?.error || 'Failed to fetch chat history');
      } finally {
        setLoading(false);
      }
    }
  };

  const handleSendMessage = async () => {
    if (!newMessage.trim() || !selectedUser) return;

    if (isChatbot) {
      // Handle chatbot interaction
      const userMessage = {
        senderId: user._id,
        senderName: user.name,
        message: newMessage.trim(),
        timestamp: new Date().toISOString(),
      };
      setMessages((prev) => [...prev, userMessage]);
      setChatbotLoading(true);

      // Get AI response
      try {
        const response = await chatAPI.getChatbotResponse(newMessage.trim());
        setMessages((prev) => [
          ...prev,
          {
            senderId: 'chatbot',
            senderName: 'AI Assistant',
            message: response.data.response,
            timestamp: new Date().toISOString(),
          },
        ]);
      } catch (err) {
        const errorMessage =
          err.response?.data?.response ||
          err.response?.data?.error ||
          'I\'m sorry, I\'m having trouble connecting right now. I recommend consulting with a staff member for assistance with your question.';

        // Fallback response if API fails
        setMessages((prev) => [
          ...prev,
          {
            senderId: 'chatbot',
            senderName: 'AI Assistant',
            message: errorMessage,
            timestamp: new Date().toISOString(),
          },
        ]);
      } finally {
        setChatbotLoading(false);
      }

      setNewMessage('');
    } else {
      try {
        const messageData = {
          receiverId: selectedUser._id,
          message: newMessage.trim(),
        };

        await chatAPI.sendMessage(messageData);
        socket.current.emit('send_message', {
          senderId: user._id,
          receiverId: selectedUser._id,
          message: newMessage.trim(),
        });

        setMessages((prev) => [
          ...prev,
          {
            senderId: user._id,
            senderName: user.name,
            message: newMessage.trim(),
            timestamp: new Date().toISOString(),
          },
        ]);
        setNewMessage('');
      } catch (err) {
        setError(err.response?.data?.error || 'Failed to send message');
      }
    }
  };

  const formatTime = (timestamp) => {
    const date = new Date(timestamp);
    return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  return (
    <div className="container-fluid py-4 bg-light min-vh-100 fade-in">
      <div className="container-fluid">
        <div className="row mb-4">
          <div className="col-12">
            <h1 className="display-5 fw-bold text-primary">💬 Chat</h1>
            <p className="lead text-muted">Get help from staff or our AI assistant</p>
          </div>
        </div>

        {error && (
          <div className="alert alert-danger alert-dismissible fade show" role="alert">
            {error}
            <button type="button" className="btn-close" onClick={() => setError('')}></button>
          </div>
        )}
        {notificationText && (
          <div className="position-fixed top-0 end-0 p-3" style={{ zIndex: 1080 }}>
            <div className="alert alert-info shadow-sm mb-0" role="alert">
              {notificationText}
            </div>
          </div>
        )}

        <div className="row g-0" style={{ height: 'calc(100vh - 200px)' }}>
          {/* Users List */}
          <div className="col-md-3 bg-white border shadow-sm">
            <div className="p-3 border-bottom">
              <h5 className="mb-0 fw-bold">Staff Members</h5>
            </div>
            <div style={{ height: 'calc(100vh - 280px)', overflowY: 'auto' }}>
              {users.length === 0 ? (
                <div className="p-3 text-muted text-center">No staff available</div>
              ) : (
                users.map((staffMember) => (
                  <button
                    key={staffMember._id}
                    className={`w-100 text-start p-3 border-bottom btn ${
                      selectedUser?._id === staffMember._id
                        ? 'bg-primary text-white'
                        : 'bg-white text-dark'
                    }`}
                    onClick={() => handleSelectUser(staffMember)}
                  >
                    <div className="fw-bold d-flex justify-content-between align-items-center">
                      <span>{staffMember.name}</span>
                      {unreadCounts[staffMember._id] > 0 && (
                        <span className="badge bg-danger rounded-pill">
                          {unreadCounts[staffMember._id]}
                        </span>
                      )}
                    </div>
                    <small>{staffMember.subject || 'Staff'}</small>
                  </button>
                ))
              )}
            </div>
          </div>

          {/* Chat Area */}
          <div className="col-md-9 d-flex flex-column bg-white">
            {selectedUser ? (
              <>
                {/* Chat Header */}
                <div className="p-3 border-bottom bg-primary text-white">
                  <h5 className="mb-0">{selectedUser.name}</h5>
                  <small>{selectedUser.subject}</small>
                </div>

                {/* Messages */}
                <div
                  className="flex-grow-1 p-3"
                  style={{ overflowY: 'auto', height: 'calc(100vh - 350px)' }}
                >
                  {loading ? (
                    <div className="text-center py-5">
                      <div className="spinner-border text-primary" role="status">
                        <span className="visually-hidden">Loading...</span>
                      </div>
                    </div>
                  ) : messages.length === 0 ? (
                    <div className="text-center text-muted py-5">
                      No messages yet. Start the conversation!
                    </div>
                  ) : (
                    messages.map((msg, index) => (
                      <div
                        key={index}
                        className={`d-flex mb-3 ${
                          msg.senderId === user._id ? 'justify-content-end' : 'justify-content-start'
                        }`}
                      >
                        <div
                          className={`p-2 rounded ${
                            msg.senderId === user._id
                              ? 'bg-primary text-white'
                              : 'bg-light text-dark'
                          }`}
                          style={{ maxWidth: '70%', wordWrap: 'break-word' }}
                        >
                          <p className="mb-1">{msg.message}</p>
                          <small className="text-muted">
                            {formatTime(msg.timestamp)}
                          </small>
                        </div>
                      </div>
                    ))
                  )}
                  {chatbotLoading && (
                    <div className="d-flex mb-3 justify-content-start">
                      <div className="p-2 rounded bg-light text-dark" style={{ maxWidth: '70%' }}>
                        <div className="d-flex align-items-center">
                          <div className="spinner-border spinner-border-sm me-2" role="status">
                            <span className="visually-hidden">Loading...</span>
                          </div>
                          <small className="text-muted">AI Assistant is typing...</small>
                        </div>
                      </div>
                    </div>
                  )}
                  <div ref={messagesEndRef} />
                </div>

                {/* Message Input */}
                <div className="p-3 border-top bg-light">
                  <div className="input-group">
                    <input
                      type="text"
                      className="form-control"
                      placeholder="Type your message..."
                      value={newMessage}
                      onChange={(e) => setNewMessage(e.target.value)}
                      onKeyPress={(e) => e.key === 'Enter' && handleSendMessage()}
                    />
                    <button
                      className="btn btn-primary"
                      type="button"
                      onClick={handleSendMessage}
                    >
                      Send
                    </button>
                  </div>
                </div>
              </>
            ) : (
              <div className="d-flex align-items-center justify-content-center h-100">
                <div className="text-center text-muted">
                  <h5>Select a staff member to start chatting</h5>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default ChatPage;
